import pygame
import time
import io
import base64

pygame.mixer.init()

DELAY = 2.2

LEFT = ""
RIGHT = ""
BOTH = ""

def play(audio):
    data = base64.b64decode(audio)
    file = io.BytesIO(data)
    sound = pygame.mixer.Sound(file)
    channel = sound.play()

    while channel.get_busy():
        time.sleep(0.01)

print("=== Stereo Test ===")
time.sleep(1)

print("LEFT")
play(LEFT)
time.sleep(DELAY)

print("RIGHT")
play(RIGHT)
time.sleep(DELAY)

print("BOTH")
play(BOTH)
time.sleep(DELAY)

print("Done")
